INSERT INTO "use_cases" VALUES (315,'Reuters Institute Digital News Report 2025','Curated','https://www.digitalnewsreport.org/','2026-05-09T14:43:55.404275+00:00','BBC trials tool to add subtitles and transcripts to BBC Sounds','BBC','United Kingdom','2025-06','https://www.digitalnewsreport.org/',NULL,'Organisation: BBC
