INSERT INTO "use_cases" VALUES (316,'Reuters Institute Digital News Report 2025','Curated','https://www.digitalnewsreport.org/','2026-05-09T14:43:55.404410+00:00','Announces AI department to deepen personalisation for younger audiences','BBC','United Kingdom','2025-06','https://www.digitalnewsreport.org/',NULL,'Organisation: BBC
Country: United Kingdom
