INSERT INTO "use_cases" VALUES (317,'Reuters Institute Digital News Report 2025','Curated','https://www.digitalnewsreport.org/','2026-05-09T14:43:55.404537+00:00','Test AI text-to-audio conversion','India Today','India','2025-06','https://www.digitalnewsreport.org/',NULL,'Organisation: India Today, Miami Herald
Country: India, United States
India Today and the Miami Herald have been testing AI technologies that allow users to turn text articles into audio, using an AI-generated voice.
