INSERT INTO "use_cases" VALUES (318,'Reuters Institute Digital News Report 2025','Curated','https://www.digitalnewsreport.org/','2026-05-09T14:43:55.404686+00:00','Tests AI text-to-audio conversion for news articles','Miami Herald','United States','2025-06','https://www.digitalnewsreport.org/',NULL,'Organisation: Miami Herald
