INSERT INTO "use_cases" VALUES (319,'Reuters Institute Digital News Report 2025','Curated','https://www.digitalnewsreport.org/','2026-05-09T14:43:55.404792+00:00','OpenAI API-powered article summaries integrated into the CMS appearing below the article lead, expandable on click','Aftonbladet','Sweden','2025-06','https://www.digitalnewsreport.org/',NULL,'Organisation: Aftonbladet
Country: Sweden
