Source: Reuters Institute Digital News Report 2025, p.50',NULL,NULL,NULL,NULL);
INSERT INTO "use_cases" VALUES (323,'Reuters Institute Digital News Report 2025','Curated','https://www.digitalnewsreport.org/','2026-05-09T14:43:55.405201+00:00','Financial Times launches generative AI tool to answer reader questions','The Financial Times','United Kingdom','2025-06','https://www.digitalnewsreport.org/',NULL,'Organisation: Financial Times
