INSERT INTO "use_cases" VALUES (938,'Nieman Lab','Industry','https://www.niemanlab.org/page/1/?s=AI+newsroom','2026-05-20T08:47:12.485026+00:00','AI tool helping generate Axios''s trademark structural elements ("why it matters," "one big thing," "the big picture"); reporters chat with the tool to get recommendations and edits rather than receiving fully automated outputs','Axios','United States','2025-11-10','https://www.nytimes.com/2025/11/07/business/media/ai-news-media.html',NULL,'“Newsquest, a British newspaper chain owned by USA Today Company, employs more than 30 journalists who use AI to delve deeper into stories. Axel Springer, the Berlin-based owner of Politico and Business Insider, recently used AI to create an interactive travel planner. Time magazine used an AI-powered chatbot for its 2024 Person of the Year featuring President Trump. The New York Times has a team that experiments with AI and builds reporting tools.”',NULL,NULL,NULL,NULL);
